axios实现vue异步请求 + 封装
安装axios &amp;&amp; vue-axios : npm install –save axios vue-axios

1.封装不同类型的请求（get,post..）,api/helpers.js配置:import Vue from &quot;vue&quot;;import axios from &quot;axios&quot;;import VueAxios from &quot;vue-axios&quot;;Vue.use(VueAxios, axios);class request &#123;    constructor() &#123;        //定义请求接口地址对象，一个是开发环境地址，另一个就是线上地址        this.urlMap = &#123;            development: &#x27;/dev&#x27;,            production: &#x27;/product&#x27;        &#125;    &#125;    //get请求    Get(obj) &#123;        //封装一层promise，一来可以把接口数据.then出去，二来解决嵌套请求的回调问题        return new Promise((resolve, reject) =&gt; &#123;            //发起axios请求            Vue.axios(                //利用ES5的浅拷贝Object.assign自动增删传入的对象                Object.assign(&#123;&#125;, &#123;                    method: &quot;get&quot;,                    //设置请求头来区分请求数据类型，formdata || json                    headers: &#123;                        &quot;Content-Type&quot;: &quot;application/x-www-form-urlencoded;charset=UTF-8&quot;                    &#125;,                    //`baseURL` 将自动加在 `url` 前面，除非 `url` 是一个绝对 URL                    baseURL: this.urlMap[process.env.NODE_ENV]                &#125;, obj)            ).then((res) =&gt; &#123;                resolve(res.data)            &#125;).catch((e) =&gt; &#123;                reject(e)            &#125;)        &#125;)    &#125;    //post请求    Post(obj) &#123;        //封装一层promise，一来可以把接口数据.then出去，二来解决嵌套请求的回调问题        return new Promise((resolve, reject) =&gt; &#123;            Vue.axios(                Object.assign(&#123;&#125;, &#123;                    method: &quot;post&quot;,                    headers: &#123;                        &quot;Content-Type&quot;: &quot;application/x-www-form-urlencoded;charset=UTF-8&quot;                    &#125;,                    baseURL: this.urlMap[process.env.NODE_ENV],                    // `transformRequest` 允许在向服务器发送前，修改请求数据                    // 只能用在 &#x27;PUT&#x27;, &#x27;POST&#x27; 和 &#x27;PATCH&#x27; 这几个请求方法                    // 后面数组中的函数必须返回一个字符串，或 ArrayBuffer，或 Stream                    transformRequest: [(data) =&gt; &#123;                        // 对 data 进行form-data处理，这个只针对后端还需要formData格式数据，如果是json则简单许多，无需区分请求方式                        let rData = &#x27;&#x27;                        for (let i in data) &#123;                            rData += encodeURIComponent(i) + &#x27;=&#x27; + encodeURIComponent(data[i]) + &#x27;&amp;&#x27;                        &#125;                        //字符串最后多了个&amp;符号，截取掉                        return rData.substr(0,rData.length-1)                    &#125;]                &#125;, obj)            ).then((res) =&gt; &#123;                resolve(res.data)            &#125;).catch((e) =&gt; &#123;                reject(e)            &#125;)        &#125;)    &#125;&#125;export &#123;    request&#125;

2.具体某接口的请求封装：api&#x2F;indexApi.js配置：import &#123;request&#125; from &#x27;../js/helper&#x27;;class homeApi extends request &#123;    //构造器    constructor() &#123;        //调用super方法，使子类自己的this对象得到父类同样的实例属性和方法        super()    &#125;    //其中的this指向子类的实例，因为上面已经完成对父类的继承    getList(data, handle) &#123;        this.Get(&#123; url: &#x27;/List?page=&#x27; + data.pageId &#125;).then((res) =&gt; &#123;            handle(res)        &#125;).catch((e) =&gt; &#123;        &#125;)    &#125;    getOther(data, handle) &#123;        //data:&#x27;mobile=&#x27;+data.mobile是form-data数据类型，&#123;data:&#123;mobile:xxxxxxx&#125;&#125;为json类型        this.Post(&#123; url: &#x27;/getOther&#x27; ,data:&#x27;mobile=&#x27;+data.mobile&#125;).then((res) =&gt; &#123;            handle(res)        &#125;).catch((e) =&gt; &#123;        &#125;)    &#125;&#125;export &#123;    homeApi&#125;

3.封装后的具体应用：app.vue:&lt;template&gt;  &lt;div class=&quot;login-wrap&quot;&gt;121212&lt;/div&gt;&lt;/template&gt;&lt;script&gt;import &#123;homeApi&#125; from &quot;../assets/api/indexApi&quot;;const Api = new homeApi()export default &#123;  data() &#123;    return &#123;&#125;;  &#125;,  mounted() &#123;    //get请求    Api.getList(      &#123;        pageId: 1      &#125;,      res =&gt; &#123;        console.log(res)      &#125;    );    //post请求    Api.getOther(      &#123;        mobile:XXXXXXXX      &#125;,      (res)=&gt;&#123;        console.log(res)      &#125;    )  &#125;&#125;;&lt;/script&gt;


