1. IM设置头像昵称要在ready之后调用tim.on(TIM.EVENT.SDK_READY, function (event) &#123;  // SDK ready 后接入侧才可以调用 sendMessage 等需要鉴权的接口，否则会提示失败！  // event.name - TIM.EVENT.SDK_READY  console.log(&quot;SDK ready&quot;, event)  // 修改个人标配资料  tim.updateMyProfile(&#123;    nick: wx.getStorageSync(&#x27;wxUserInfo&#x27;).nickName,    avatar: wx.getStorageSync(&#x27;wxUserInfo&#x27;).avatarUrl  &#125;).then(function (imResponse) &#123;    console.log(imResponse.data); // 更新资料成功  &#125;).catch(function (imError) &#123;    console.warn(&#x27;updateMyProfile error:&#x27;, imError); // 更新资料失败的相关信息  &#125;);&#125;)

2.有成员加群回调只有调用登录tim.login方法 再调用加群tim.joinGroup方法 才会触发示例：
//登录IMtim.login(&#123;  userID: uid, //用户ID后台返回的用户ID  userSig: data.data.UserSig //后台返回的根据用户ID生成的加密串&#125;).then(function (imResponse) &#123;  console.log(&quot;登录成功&quot;, imResponse.data); // 登录成功  tim.joinGroup(&#123;    groupID: that.data.groupID,  //群ID    type: TIM.TYPES.GRP_AVCHATROOM //类型为直播群必填字段  &#125;).then(function (imResponse) &#123;    console.log(&quot;加群成功&quot;, imResponse)    switch (imResponse.data.status) &#123;      case TIM.TYPES.JOIN_STATUS_SUCCESS: // 加群成功        // console.log(imResponse.data.group) // 加入的群组资料        break      case TIM.TYPES.JOIN_STATUS_ALREADY_IN_GROUP: // 已经在群中        break      default:        break    &#125;  &#125;).catch(function (imError) &#123;    console.warn(&#x27;加群失败&#x27;, imError) // 申请加群失败的相关信息  &#125;);  resolve(imResponse)&#125;).catch(function (imError) &#123;  console.warn(&#x27;登录IM失败:&#x27;, imError); // 登录失败的相关信息  reject(imError)&#125;);

3.判断是否被禁言，调用发消息（包括各种类型的消息）前先判断是否被禁言，如果禁言调用发消息会报错（注意必须在SDK_READY之后调用）示例：
//判断是否被禁言checkUserBanned() &#123;  let that = this;  return new Promise((resolve, reject) =&gt; &#123;    tim.getGroupMemberProfile(&#123;      groupID: that.data.groupID,      userIDList: [wx.getStorageSync(&#x27;userInfo&#x27;).uid] //用户ID，必须为数组    &#125;).then(function (imResponse) &#123;      // console.log(imResponse.data.memberList); // 群成员列表      resolve(imResponse.data.memberList)    &#125;).catch(function (imError) &#123;      // console.warn(&#x27;getGroupMemberProfile error:&#x27;, imError);      reject(imError)    &#125;);  &#125;)&#125;,//检查是否被禁言,这样调用还有个弊端，每次发消息都会请求禁言接口，导致发消息很慢，所以我优化成了调用login时判断此用户是否被禁言that.checkUserBanned().then((res) =&gt; &#123;  for (let groupMember of res) &#123;    if (groupMember.muteUntil * 1000 &gt; Date.now()) &#123;      //禁言中      wx.showToast(&#123;        title: &#x27;您已被禁言&#x27;,        icon: &quot;none&quot;      &#125;)    &#125; else &#123;      //未禁言      let message = tim.createCustomMessage(&#123;        to: that.data.groupID,        conversationType: TIM.TYPES.CONV_GROUP,        payload: &#123;          data: &#x27;&#x27;, // 用于标识该消息是什么类型自定义消息          description: that.liveId, // 直播ID          extension: number + &quot;&quot; //         &#125;      &#125;);      // 3. 发送消息      let promise = tim.sendMessage(message);      promise.then(function (imResponse) &#123;        // 发送成功        console.log(imResponse);      &#125;).catch(function (imError) &#123;        // 发送失败        console.warn(&#x27;sendMessage error:&#x27;, imError);      &#125;);    &#125;  &#125;&#125;)

4.进场消息、购买消息等只显示一次，并且显示时间相同的消息实现
基本原理就是onShow生命周期触发一个定时器方法，在收到进群消息或购买消息回调之后，把收到的消息push到一个相同的数组中，然后页面只展示第一条数组，因为动画是三秒一条消息，所以定时器三秒轮询一次，第一条三秒之后删除，这样不会导致数组内存过大，示例：onShow()&#123;  this.tipMsg()&#125;,buyMessage(message) &#123;  //收到购买消息回调之后，往tipsData数组push一条数据，定时器监测到有数据便会渲染出来  let that = this;  let res = &#123;&#125;;  res.avatar = message.avatar;  res.nick = message.nick;  res.type = 3;  that.data.tipsData.push(res)&#125;,tipMsg() &#123;  let that = this;  that.tipTimer = setInterval(() =&gt; &#123;    if (that.data.tipsData.length &gt; 0) &#123;      that.setData(&#123;        tipsDatas: that.data.tipsData[0] //这里的tipsData对象便是要渲染到页面中的单条数据      &#125;)      that.tipAnimation()    &#125;  &#125;, 3000);&#125;,tipAnimation() &#123;  let that = this;  let animation = wx.createAnimation(&#123;    duration: 300  &#125;)  animation.translateX(0).step()  that.setData(&#123;    animationData: animation.export()  &#125;)  setTimeout(() =&gt; &#123;    animation.translateX(&#x27;-100%&#x27;).step(&#123;      duration: 0    &#125;)    that.setData(&#123;      animationData: animation.export()    &#125;)    that.data.tipsData.shift()    // console.log(that.data.tipsData)  &#125;, 2700);&#125;,

tips：这样应该不是最优解，毕竟定时器触发还是有点耗性能的，loading…
这样做下来直播IM还是相对简单的，毕竟用的API还没有十分之一，很多API都是聊天群才用到的
